inline int mirror_index_int(int d, int sizeD)
{
    if (sizeD <= 1) return 0;
    if (d >= sizeD) {
        d = 2 * sizeD - 2 - d;
    } else if (d < 0) {
        d = -d;
    }
    if (d < 0) d = 0;
    if (d >= sizeD) d = sizeD - 1;
    return d;
}

inline int read_input_mirror(__global const int *input, int sizeX, int sizeY, int x, int y)
{
    x = mirror_index_int(x, sizeX);
    y = mirror_index_int(y, sizeY);
    return input[y * sizeX + x];
}

inline int vhigh_from_input(__global const int *input, int sizeX, int sizeY, int x, int hy)
{
    const int y0 = 2 * hy;
    const int y1 = y0 + 1;
    const int y2 = y0 + 2;

    const int s0 = read_input_mirror(input, sizeX, sizeY, x, y0);
    const int s1 = read_input_mirror(input, sizeX, sizeY, x, y1);
    const int s2 = read_input_mirror(input, sizeX, sizeY, x, y2);

    return s1 - (s0 + s2) / 2;
}

inline int vlow_from_input(__global const int *input, int sizeX, int sizeY, int x, int ly)
{
    const int evenv = read_input_mirror(input, sizeX, sizeY, x, 2 * ly);
    const int d0 = vhigh_from_input(input, sizeX, sizeY, x, ly - 1);
    const int d1 = vhigh_from_input(input, sizeX, sizeY, x, ly);

    return evenv + (d0 + d1 + 2) / 4;
}

inline int hhigh_from_vlow(__global const int *input, int sizeX, int sizeY, int hx, int ly)
{
    const int x0 = 2 * hx;
    const int x1 = x0 + 1;
    const int x2 = x0 + 2;

    const int s0 = vlow_from_input(input, sizeX, sizeY, x0, ly);
    const int s1 = vlow_from_input(input, sizeX, sizeY, x1, ly);
    const int s2 = vlow_from_input(input, sizeX, sizeY, x2, ly);

    return s1 - (s0 + s2) / 2;
}

inline int hlow_from_vlow(__global const int *input, int sizeX, int sizeY, int lx, int ly)
{
    const int evenv = vlow_from_input(input, sizeX, sizeY, 2 * lx, ly);
    const int d0 = hhigh_from_vlow(input, sizeX, sizeY, lx - 1, ly);
    const int d1 = hhigh_from_vlow(input, sizeX, sizeY, lx, ly);

    return evenv + (d0 + d1 + 2) / 4;
}

inline int hhigh_from_vhigh(__global const int *input, int sizeX, int sizeY, int hx, int hy)
{
    const int x0 = 2 * hx;
    const int x1 = x0 + 1;
    const int x2 = x0 + 2;

    const int s0 = vhigh_from_input(input, sizeX, sizeY, x0, hy);
    const int s1 = vhigh_from_input(input, sizeX, sizeY, x1, hy);
    const int s2 = vhigh_from_input(input, sizeX, sizeY, x2, hy);

