inline int hlow_from_vhigh(__global const int *input, int sizeX, int sizeY, int lx, int hy)
{
    const int evenv = vhigh_from_input(input, sizeX, sizeY, 2 * lx, hy);
    const int d0 = hhigh_from_vhigh(input, sizeX, sizeY, lx - 1, hy);
