__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    const int pixels)
{
    const int gid = (int)get_global_id(0);

    if (gid < pixels) {
        const int base = gid * 3;
        d_r[gid] = (int)d_src[base + 0] - 128;
        d_g[gid] = (int)d_src[base + 1] - 128;
        d_b[gid] = (int)d_src[base + 2] - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   const int pixels)
{
    const int gid0 = (int)get_global_id(0);
    const int base = gid0 * 9;

    for (int k = 0; k < 9; ++k) {
        const int i = base + k;
        if (i < pixels) {
            d_c[i] = (int)d_src[i] - 128;
        }
    }
}

__kernel void cl_fdwt53Kernel(__global const int *input,
                              __global int *output,
                              const int sizeX,
                              const int sizeY,
                              const int steps,
                              const int WIN_SX,
                              const int WIN_SY)
{
    (void)steps;
    (void)WIN_SX;
    (void)WIN_SY;

    const int x = (int)get_global_id(0);
    const int yStart = (int)get_global_id(1);
    const int yStride = (int)get_global_size(1);

    const int llx = (sizeX + 1) / 2;
    const int hlx = sizeX - llx;
    const int lly = (sizeY + 1) / 2;
    const int hly = sizeY - lly;

    const int offLL = 0;
    const int offHL = llx * lly;
    const int offLH = offHL + hlx * lly;
    const int offHH = offLH + llx * hly;

    if (x < llx) {
        for (int ly = yStart; ly < lly; ly += yStride) {
            output[offLL + ly * llx + x] = hlow_from_vlow(input, sizeX, sizeY, x, ly);
        }

        for (int hy = yStart; hy < hly; hy += yStride) {
            output[offLH + hy * llx + x] = hlow_from_vhigh(input, sizeX, sizeY, x, hy);
        }
    }

    if (x < hlx) {
        for (int ly = yStart; ly < lly; ly += yStride) {
            output[offHL + ly * hlx + x] = hhigh_from_vlow(input, sizeX, sizeY, x, ly);
        }

        for (int hy = yStart; hy < hly; hy += yStride) {
            output[offHH + hy * hlx + x] = hhigh_from_vhigh(input, sizeX, sizeY, x, hy);
        }
    }
}
